// Real example: V8 (Chrome's JS engine) uses INSERTION SORT for small subarrays
// inside its main sorting routine — even though insertion sort is O(n²)!
//
// Why? For tiny arrays (~10 items), the simplicity wins:
// no recursion overhead, branch prediction is great, fits in cache.
//
// Insertion sort outperforms merge sort here despite being asymptotically worse.

function insertionSort(arr) {
  for (let i = 1; i < arr.length; i++) {
    const cur = arr[i];
    let j = i - 1;
    while (j >= 0 && arr[j] > cur) {
      arr[j + 1] = arr[j];
      j--;
    }
    arr[j + 1] = cur;
  }
  return arr;
}

console.log(insertionSort([5, 2, 4, 6, 1, 3]));

// CONTRIVED but illustrative: same input, two implementations.
// One is asymptotically better. The other is faster on real input.

// Both find the max in an array.

// Version A: clean O(n) loop.
function maxLinear(arr) {
  let m = arr[0];
  for (let i = 1; i < arr.length; i++) {
    if (arr[i] > m) m = arr[i];
  }
  return m;
}

// Version B: also O(n) but uses Math.max with spread,
// which is bad for very large arrays (stack overflow risk).
function maxSpread(arr) {
  return Math.max(...arr);
}

const small = Array.from({ length: 100 }, () => Math.random());
const big   = Array.from({ length: 100000 }, () => Math.random());

console.log('small array, both fine');
console.log('linear:', maxLinear(small));
console.log('spread:', maxSpread(small));

console.log('big array, both still fine — but spread allocates a new arg list');
console.log('linear:', maxLinear(big).toFixed(4));
console.log('spread:', maxSpread(big).toFixed(4));

// Same Big O. Different real-world behavior.
